const t={configTemplates:{intro:{t:0,b:{t:2,i:[{t:3}],s:"كتل تهيئة وماكروهات Klipper جاهزة للّصق — تسلسلات البدء، والتعامل مع الخيط، وتشكيل الإدخال، وشبكة السرير وغيرها. انسخ واحدة وأسقطها في ملف printer.cfg (محرّر التهيئة مكان مناسب للّصق)."}},help:{guide:{t:0,b:{t:2,i:[{t:3}],s:"مساعدة"}},guideTitle:{t:0,b:{t:2,i:[{t:3}],s:"حول قوالب التهيئة"}},close:{t:0,b:{t:2,i:[{t:3}],s:"إغلاق"}},howToRead:{t:0,b:{t:2,i:[{t:3}],s:"كيفية الاستخدام"}},steps:[{t:0,b:{t:2,i:[{t:3}],s:"رشّح حسب الفئة للعثور على ماكرو أو كتلة تهيئة."}},{t:0,b:{t:2,i:[{t:3}],s:"اقرأ الوصف والأقسام التي يحتاجها."}},{t:0,b:{t:2,i:[{t:3}],s:"انسخ القالب، والصقه في تهيئتك، واضبط القيم."}}],topics:{what:{title:{t:0,b:{t:2,i:[{t:3}],s:"ما هذه القوالب"}},body:{t:0,b:{t:2,i:[{t:3}],s:"مجموعة منسَّقة من لبنات Klipper الشائعة: ماكروهات gcode_macro (مثل PRINT_START، وPAUSE/RESUME، وتحميل/تفريغ الخيط، وM600) وأقسام تهيئة (مثل [input_shaper]، و[bed_mesh]، و[firmware_retraction]، …). إنها نقاط انطلاق — اقرأ كلًّا منها واضبطه لطابعتك."}}},insert:{title:{t:0,b:{t:2,i:[{t:3}],s:"إدراج قالب"}},body:{t:0,b:{t:2,i:[{t:3}],s:"انسخ قالبًا، ثم الصقه في ملف printer.cfg — العرض الخام في محرّر التهيئة مكان مناسب. بعد الحفظ، تؤدّي إعادة تشغيل البرنامج الثابت إلى تطبيقه. راجع القيم أولًا دائمًا؛ القيم الافتراضية هنا معقولة لكنها غير مضبوطة لطابعتك."}}},sections:{title:{t:0,b:{t:2,i:[{t:3}],s:"الأقسام المطلوبة"}},body:{t:0,b:{t:2,i:[{t:3}],s:"يسرد كل قالب أقسام التهيئة التي يُعرّفها أو يعتمد عليها. إذا كان قسمٌ موجودًا بالفعل في تهيئتك، فادمج المفاتيح بدلًا من لصق نسخة مكرّرة (يُرفض القسم المكرّر عند بدء التشغيل)."}}},glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"مسرد المصطلحات"}},body:{t:0,b:{static:"",t:2,i:[]}}}},glossary:{template:{term:{t:0,b:{t:2,i:[{t:3}],s:"قالب"}},def:{t:0,b:{t:2,i:[{t:3}],s:"مقتطف جاهز للّصق من تهيئة Klipper أو ماكرو G-code تنسخه إلى ملف printer.cfg."}}},macro:{term:{t:0,b:{t:2,i:[{t:3}],s:"gcode_macro"}},def:{t:0,b:{t:2,i:[{t:3}],s:"أمر مُسمّى تُعرّفه في التهيئة (مثل PRINT_START) يُنفّذ تسلسلًا من أوامر G-code."}}},section:{term:{t:0,b:{t:2,i:[{t:3}],s:"قسم"}},def:{t:0,b:{t:2,i:[{t:3}],s:"كتلة تهيئة بين [أقواس مربّعة]، مثل [bed_mesh] — الوحدة التي تُجمَّع فيها تهيئة Klipper."}}}}},category:{label:{t:0,b:{t:2,i:[{t:3}],s:"الفئة"}},all:{t:0,b:{t:2,i:[{t:3}],s:"كل الفئات"}}},template:{copy:{t:0,b:{t:2,i:[{t:3}],s:"نسخ"}},copied:{t:0,b:{t:2,i:[{t:3}],s:"تم النسخ!"}},requires:{t:0,b:{t:2,i:[{t:3,v:"الأقسام: "},{t:4,k:"sections"}]}},requiresNone:{t:0,b:{t:2,i:[{t:3}],s:"—"}}},count:{t:0,b:{t:2,i:[{t:4,k:"n"},{t:3,v:" قوالب"}]}},states:{loading:{t:0,b:{t:2,i:[{t:3}],s:"جارٍ تحميل القوالب…"}},error:{t:0,b:{t:2,i:[{t:3}],s:"تعذّر تحميل القوالب."}},empty:{t:0,b:{t:2,i:[{t:3}],s:"لا توجد قوالب في هذه الفئة."}},retry:{t:0,b:{t:2,i:[{t:3}],s:"إعادة المحاولة"}}}}};export{t as default};
